mapper.select:
SELECT
    t.id,
    t.task_name as title,
    t.type,
    CONCAT(a.province, a.city, a.district) as area_name,
    p.name as pipe_name,
    t.priority,
    t.status,
    r.name as assignee,
    r.phone,
    t.public_time,
    t.response_time,
    t.accomplish_time,
    t.feedback_information
FROM task t
LEFT JOIN repairman r ON t.repairman_id = r.id
LEFT JOIN area a ON t.area_id = a.id
LEFT JOIN pipe p ON t.pipe_id = p.id


        AND t.inspection_id = #{inspectionId}


        AND t.repairman_id = #{repairmanId}


        AND t.area_id = #{areaId}


        AND t.pipe_id = #{pipeId}


        AND t.type = #{type}


        AND t.priority = #{priority}


        AND t.status = #{status}


        AND t.create_time >= #{startTime}


        AND t.create_time <= #{endTime}


ORDER BY t.create_time DESC

